import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useParams, Navigate } from 'react-router-dom';
import { Music, Trophy, Search, User, LogOut, Upload, ListMusic, Disc } from 'lucide-react';

// Import các trang (Hãy đảm bảo bạn đã tạo các file này trong thư mục pages)
import Home from './pages/Home/Home';
import SearchPage from './pages/Search/Search';
import Ranking from './pages/Ranking/Ranking';
import Profile from './pages/Profile/Profile';
import FocusMode from './pages/Focus/FocusMode';
import Login from './pages/Auth/Login';
import Register from './pages/Auth/Register';
import AdminUpload from './pages/Admin/AdminUpload';

// --- MỚI: Import các trang Playlist ---
// import UserPlaylists from './pages/Playlist/UserPlaylists'; 
// import PlaylistDetail from './pages/Playlist/PlaylistDetail';

// --- BỘ PHẬN TRUNG GIAN ÉP PROFILE LOAD LẠI ---
const ProfileWrapper = () => {
  const { userId } = useParams();
  return <Profile key={userId} />;
};

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));

  // Theo dõi sự thay đổi của localStorage để cập nhật UI ngay lập tức
  useEffect(() => {
    const handleStorageChange = () => {
      setUser(JSON.parse(localStorage.getItem('user')));
    };
    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, []);

  const handleLogout = () => {
    if (window.confirm("Bạn có chắc chắn muốn đăng xuất?")) {
      localStorage.clear();
      setUser(null);
      window.location.href = '/login';
    }
  };

  return (
    <Router>
      {/* THANH ĐIỀU HƯỚNG (NAVBAR) */}
      <nav style={navBarStyle}>
        <div style={{ display: 'flex', gap: '25px', alignItems: 'center' }}>
          <Link to="/" style={logoStyle}>
            <Disc size={28} /> P2TUNES
          </Link>
          <Link to="/search" style={navLinkStyle}><Search size={18} /> Tìm kiếm</Link>
          <Link to="/ranking" style={navLinkStyle}><Trophy size={18} /> BXH</Link>
          <Link to="/focus" style={navLinkStyle}>Focus</Link>
          
          {/* Menu cho người đã đăng nhập */}
          {user && (
            <>
              <Link to="/upload" style={uploadBtnStyle}><Upload size={16} /> Đăng nhạc</Link>
              <Link to={`/playlists/user/${user._id || user.id}`} style={navLinkStyle}>
                <ListMusic size={18} /> Thư viện
              </Link>
            </>
          )}
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          {user ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              <Link 
                to={`/profile/${user._id || user.id}`} 
                style={{ textDecoration: 'none', color: 'white', display: 'flex', alignItems: 'center', gap: '5px' }}
              >
                <div style={avatarCircle}>{user.username?.charAt(0).toUpperCase()}</div>
                <span>{user.username}</span>
                {user.role === 'admin' && <span style={adminBadge}>Admin</span>}
              </Link>
              <button onClick={handleLogout} style={logoutBtnStyle}>
                <LogOut size={16} /> Thoát
              </button>
            </div>
          ) : (
            <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
              <Link to="/login" style={navLinkStyle}>Đăng nhập</Link>
              <Link to="/register" style={registerBtnStyle}>Tham gia miễn phí</Link>
            </div>
          )}
        </div>
      </nav>

      {/* NỘI DUNG CHÍNH */}
      <div style={{ minHeight: '85vh', background: '#f8f9fa' }}>
        <Routes>
          {/* Public Routes */}
          <Route path="/" element={<Home />} />
          <Route path="/search" element={<SearchPage />} />
          <Route path="/ranking" element={<Ranking />} />
          <Route path="/focus" element={<FocusMode />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          
          {/* Profile Route với Wrapper */}
          <Route path="/profile/:userId" element={<ProfileWrapper />} />

          {/* Private Routes (Yêu cầu đăng nhập) */}
          <Route 
            path="/upload" 
            element={user ? <AdminUpload /> : <Navigate to="/login" />} 
          />
          
          {/* MỚI: Routes cho Playlist (Bạn sẽ tạo component sau) */}
          <Route 
            path="/playlists/user/:userId" 
            element={user ? <div style={{padding: '50px'}}>Trang Thư viện Playlist đang phát triển...</div> : <Navigate to="/login" />} 
          />
          <Route 
            path="/playlist/:playlistId" 
            element={<div style={{padding: '50px'}}>Trang Chi tiết Playlist đang phát triển...</div>} 
          />

          {/* Fallback cho URL không tồn tại */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </div>

      <footer style={footerStyle}>
        <div style={{ marginBottom: '10px', color: '#333', fontWeight: 'bold' }}>P2TUNES MUSIC</div>
        <div>© 2025 - Dự án tốt nghiệp Đại học. Nền tảng chia sẻ âm nhạc phi lợi nhuận.</div>
      </footer>
    </Router>
  );
}

// --- HỆ THỐNG CSS (Tối ưu giao diện sạch sẽ, hiện đại) ---
const navBarStyle = { 
  padding: '10px 60px', 
  background: '#1db954', 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  boxShadow: '0 4px 12px rgba(0,0,0,0.1)', 
  color: 'white', 
  position: 'sticky', 
  top: 0, 
  zIndex: 1100 
};

const logoStyle = { 
  fontWeight: '900', 
  textDecoration: 'none', 
  color: 'white', 
  fontSize: '22px', 
